                    { name: "AE",     formula: "(I − F) / I × 100%",         unit: "%" },
                    { name: "NPE",    formula: "P / A × 100%",               unit: "%" },
                    { name: "EE",     formula: "P_n+1 / P_n × 100%",         unit: "%" },
                    { name: "Budget", formula: "I = P + R + F",              unit: "kJ" }
